package ua.university.sms.repository;import org.springframework.data.jpa.repository.*;import ua.university.sms.model.entity.Enrollment;import java.util.*;
public interface EnrollmentRepository extends JpaRepository<Enrollment,Long>{boolean existsByStudentIdAndCourseId(Long studentId,Long courseId);List<Enrollment> findByStudentId(Long studentId);List<Enrollment> findByCourseId(Long courseId);@Query("select avg(e.grade) from Enrollment e where e.course.id=:courseId and e.grade is not null")Double averageGpaByCourse(Long courseId);@Query("select avg(e.grade) from Enrollment e where e.course.semester=:semester and e.grade is not null")Double averageGpaBySemester(String semester);}
